package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.RszPlafondPercentage;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.service.RszPlafondPercentageService;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import lombok.Data;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class CachedRszPlafondPercentageService implements CachedService, RszPlafondPercentageService {

    @Autowired
    private RszPlafondPercentageService rszPlafondPercentageService;

    private static final ThreadLocal<CachedRszPlafondPercentageBuffer> BUFFER = new ThreadLocal<>();

    public CachedRszPlafondPercentageService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }

    @Override
    public RszPlafondPercentage getByWerkgeversCategorieEnWerknemersKengetalEnDatum(
            WerkgeversCategorie werkgeversCategorie,
            DmfapplWnkengetal werknemersKengetal, LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("CachedRszPlafondPercentageService.getByWerkgeversCategorieEnWerknemersKengetalEnDatum");
        CachedRszPlafondPercentageBuffer buffer = CachedRszPlafondPercentageService.getBuffer();
        RszPlafondPercentageKey key = new RszPlafondPercentageKey(werkgeversCategorie, werknemersKengetal);
        List<RszPlafondPercentage> lijst = buffer.get1(key);
        if (lijst == null) {
            lijst = rszPlafondPercentageService.findByWerkgeversCategorieEnWerknemersKengetal(werkgeversCategorie, werknemersKengetal);
            buffer.put1(key, lijst);
        }

        RszPlafondPercentage result = zoekLijst(lijst, datum);
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    private RszPlafondPercentage zoekLijst(List<RszPlafondPercentage> lijst, LocalDate datum) {
        RszPlafondPercentage result = null;
        for (RszPlafondPercentage RszPlafondPercentage : lijst) {
            LocalDateInterval periode = new LocalDateInterval(RszPlafondPercentage.getBeginDatum(), RszPlafondPercentage.getEindDatum());
            if (periode.contains(datum)) {
                result = RszPlafondPercentage;
                break;
            }
        }
        return result;
    }


    @Override
    public void clearCache() {
        CachedRszPlafondPercentageService.getBuffer().clear();
    }

    private static class CachedRszPlafondPercentageBuffer {

        private final Map<RszPlafondPercentageKey, List<RszPlafondPercentage>> RszPlafondPercentageBuffer = new HashMap<>();

        public List<RszPlafondPercentage> get1(RszPlafondPercentageKey key) {
            return RszPlafondPercentageBuffer.get(key);
        }

        public void put1(RszPlafondPercentageKey key, List<RszPlafondPercentage> lijst) {
            RszPlafondPercentageBuffer.put(key, lijst);
        }

        public void clear() {
            RszPlafondPercentageBuffer.clear();
        }
    }

    private static CachedRszPlafondPercentageBuffer getBuffer() {
        CachedRszPlafondPercentageBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedRszPlafondPercentageBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    @Data
    private static class RszPlafondPercentageKey {

        private final int werkgeversCategorie;
        private final int werknemersKengetal;

        RszPlafondPercentageKey(WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal) {
            this.werkgeversCategorie = werkgeversCategorie.getCode();
            this.werknemersKengetal = werknemersKengetal.getCode();
        }
    }


    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public List<RszPlafondPercentage> findByWerkgeversCategorieEnWerknemersKengetal(WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal) {
        return rszPlafondPercentageService.findByWerkgeversCategorieEnWerknemersKengetal(werkgeversCategorie, werknemersKengetal);
    }


    @Override
    public RszPlafondPercentage getById(Integer id) {
        return rszPlafondPercentageService.getById(id);
    }

    @Override
    public RszPlafondPercentage getById(Integer id, String fetchFields) {
        return rszPlafondPercentageService.getById(id, fetchFields);
    }

    @Override
    public List<RszPlafondPercentage> findAll() {
        return rszPlafondPercentageService.findAll();
    }

    @Override
    public RszPlafondPercentage create(RszPlafondPercentage constant) {
        return rszPlafondPercentageService.create(constant);
    }

    @Override
    public void update(RszPlafondPercentage constant) {
        rszPlafondPercentageService.update(constant);
    }

    @Override
    public void delete(RszPlafondPercentage constant) {
        rszPlafondPercentageService.delete(constant);
    }

    @Override
    public RszPlafondPercentage getByCriteria(CriteriaBuilder cb) {
        return rszPlafondPercentageService.getByCriteria(cb);
    }


    @Override
    public List<RszPlafondPercentage> findAll(String fetchFields) {
        return rszPlafondPercentageService.findAll(fetchFields);
    }

    @Override
    public List<RszPlafondPercentage> findByCriteria(CriteriaBuilder cb) {
        return rszPlafondPercentageService.findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return rszPlafondPercentageService.countByCriteria(cb);
    }

    @Override
    public Map<Integer, RszPlafondPercentage> cacheByCriteria(CriteriaBuilder cb) {
        return rszPlafondPercentageService.cacheByCriteria(cb);
    }

    @Override
    public RszPlafondPercentage getByCriteriaTemporalFree(CriteriaBuilder cb) {
        return rszPlafondPercentageService.getByCriteriaTemporalFree(cb);
    }

    @Override
    public List<RszPlafondPercentage> findByCriteriaTemporalFree(CriteriaBuilder cb) {
        return rszPlafondPercentageService.findByCriteriaTemporalFree(cb);
    }

}
